            return true
        }
    },
    SUNDAY {
        override fun getDayName(): String {
            return "Sunday"
        }

        override fun isWeekend(): Boolean {
            return true
        }
    };

    abstract fun getDayName(): String
    abstract fun isWeekend(): Boolean
}
```

In this example, the `Weekday` enum class has no default constructor. Instead, each enum constant overrides the `getDayName()` and `isWeekend()` functions to provide custom implementations.

You can access these functions as follows:

```kotlin
val monday = Weekday.MONDAY
println(monday.getDayName()) // Output: Monday
println(monday.isWeekend()) // Output: false
```

Similarly, you can access the `getDayName()` and `isWeekend()` functions for other enum constants.

By providing abstract functions in the enum class, each enum constant can have its own implementation. This approach allows you to create an enum class without relying on a default constructor for the enum constants.
